+import { Component, OnInit } from '@angular/core';
+import { ActivatedRoute } from '@angular/router';
+import { CommonService } from '../../../service/common.service';
+import { environment } from '../../../../environments/environment';
+import { ApiNameConstants } from '../../../constant/ApiNameConstants';
+import { ApiModel } from '../../../model/ApiModel';
+import { ConstantsApp } from '../../../constant/ConstantsApp';
+
+@Component({
+  selector: 'app-company-detail',
+  templateUrl: './company-detail.component.html',
+  styleUrls: ['./company-detail.component.scss']
+})
+export class CompanyDetailComponent implements OnInit {
+  companyId: number | null = null;
+  company: any = null;
+  jobs: any[] = [];
+  isLoading = true;
+  currentPage = 0;
+  totalPages = 1;
+  pageSize = 10;
+
+  constructor(
+    private route: ActivatedRoute,
+    private commonService: CommonService
+  ) { }
+
+  ngOnInit(): void {
+    this.route.params.subscribe(params => {
+      this.companyId = +params['id'];
+      if (this.companyId) {
+        this.loadOrganizationDetail();
+      }
+    });
+  }
+
+  loadOrganizationDetail(): void {
+    this.isLoading = true;
+
+    const body = { organizationId: this.companyId };
+
+    const apiModels: ApiModel[] = [
+      new ApiModel(
+        'get organization detail',
+        environment.API_URI + ApiNameConstants.BS_ORG_JOBS_BY_ORG,
+        body,
+        ConstantsApp.POST
+      )
+    ];
+
+    this.commonService.retrieveData(apiModels).subscribe({
+      next: (response: any) => {
+        const res = response?.[0];
+        if (res) {
+          // Lấy thông tin công ty
+          this.company = res.organization;
+          // Lấy danh sách việc làm
+          this.jobs = res.jobs || [];
+          this.totalPages = Math.ceil(this.jobs.length / this.pageSize);
+        }
+        this.isLoading = false;
+      },
+      error: (err) => {
+        console.error('Error fetching organization detail', err);
+        this.isLoading = false;
+      }
+    });
+  }
+
+  onPageChange(page: number) {
+    this.currentPage = page;
+  }
+}

