+import { Component, OnInit, ViewChild } from '@angular/core';
+import { ActivatedRoute } from '@angular/router';
+import { CommonService } from '../../../service/common.service';
+import { environment } from '../../../../environments/environment';
+import { ApiModel } from '../../../model/ApiModel';
+import { ConstantsApp } from '../../../constant/ConstantsApp';
+import { ApiNameConstants } from 'src/app/constant/ApiNameConstants';
+import { JobItemsListComponent } from '../../home/job-items-list/job-items-list.component';
+
+interface CompanyDetail {
+  id: number;
+  name: string;
+  avatar: string;
+  description: string;
+  website: string;
+  address: string;
+  province: string;
+  ward: string;
+  employeeCount: string;
+  followerCount: number;
+  isPro: boolean;
+  establishedYear: number;
+  industry: string;
+}
+
+interface JobPosting {
+  id: number;
+  title: string;
+  companyName: string;
+  location: string;
+  salary: string;
+  deadline: string;
+  isPro: boolean;
+  description: string;
+}
+
+
+@Component({
+  selector: 'app-company-detail',
+  templateUrl: './company-detail.component.html',
+  styleUrls: ['./company-detail.component.scss']
+})
+export class CompanyDetailComponent implements OnInit {
+  @ViewChild('itemsListRef') itemsListRef!: JobItemsListComponent;
+  pageNum = 1;
+  companyId: number | null = null;
+  company: CompanyDetail | null = null;
+  dataSource: JobPosting[] = [];
+  isLoading = true;
+  authenticated: boolean;
+  // Pagination
+  pageSize = 10;
+  totalPages = 1;
+
+  constructor(
+    private route: ActivatedRoute,
+    private commonService: CommonService
+  ) { }
+
+  ngOnInit(): void {
+    this.authenticated = this.authService.authenticated();
+    this.route.params.subscribe(params => {
+      this.companyId = +params['id'];
+      if (this.companyId) {
+        this.loadOrganizationDetail();
+      }
+    });
+  }
+
+  loadOrganizationDetail(): void {
+    if (!this.companyId) return;
+
+    const apiUrl = environment.API_URI + ApiNameConstants.BS_JOBS_BY_ORG;
+    const urlWithParam = `${apiUrl}?organizationId=${this.companyId}`;
+
+    const apiModels: ApiModel[] = [
+      new ApiModel('get organization detail', urlWithParam, null, ConstantsApp.POST)
+    ];
+
+    this.commonService.retrieveData(apiModels).subscribe({
+      next: (response: any) => {
+        this.isLoading = false;
+        if (response && response[0]) {
+          const data = response[0];
+          const org = data.organization;
+          this.company = {
+            id: org.id,
+            name: org.name,
+            avatar: org.avatar || 'https://img.icons8.com/color/64/company.png',
+            description: org.description || 'Công ty chuyên nghiệp với nhiều năm kinh nghiệm.',
+            website: org.website || '',
+            address: org.province ? `${org.ward}, ${org.province}` : 'Địa chỉ chưa cập nhật',
+            province: org.province || '',
+            ward: org.ward || '',
+            employeeCount: '100-499 nhân viên',
+            followerCount: Math.floor(Math.random() * 200) + 50,
+            isPro: true,
+            establishedYear: org.creationDate ? new Date(org.creationDate).getFullYear() : 2010,
+            industry: org.industry || this.getIndustryFromName(org.name)
+          };
+
+          this.dataSource = (data.jobs || []).map((job: any) => ({
+            id: job.id,
+            title: job.name || job.title,
+            companyName: this.company?.name || '',
+            location: job.province || 'Hồ Chí Minh',
+            salary: job.salary || 'Thỏa thuận',
+            deadline: job.expDate || job.deadline || '',
+            isPro: true,
+            description: job.des || job.description || ''
+          }));
+
+          this.totalPages = Math.ceil(this.dataSource.length / this.pageSize);
+        }
+      },
+      error: (err) => {
+        console.error('Error loading organization detail:', err);
+        this.isLoading = false;
+      }
+    });
+  }
+
+  onPageChange(newPage: number) {
+    this.pageNum = newPage;
+  }
+
+
+
+  getIndustryFromName(name: string): string {
+    const nameLower = name.toLowerCase();
+    if (nameLower.includes('ngân hàng') || nameLower.includes('bank')) return 'Ngân hàng';
+    if (nameLower.includes('bất động sản') || nameLower.includes('real estate')) return 'Bất động sản';
+    if (nameLower.includes('xây dựng') || nameLower.includes('construction')) return 'Xây dựng';
+    if (nameLower.includes('it') || nameLower.includes('software') || nameLower.includes('tech')) return 'IT - Phần mềm';
+    if (nameLower.includes('tài chính') || nameLower.includes('finance')) return 'Tài chính';
+    if (nameLower.includes('bán lẻ') || nameLower.includes('retail')) return 'Bán lẻ - Hàng tiêu dùng - FMCG';
+    if (nameLower.includes('sản xuất') || nameLower.includes('manufacturing')) return 'Sản xuất';
+    if (nameLower.includes('viễn thông') || nameLower.includes('telecom')) return 'Viễn thông';
+    if (nameLower.includes('bảo hiểm') || nameLower.includes('insurance')) return 'Bảo hiểm';
+    if (nameLower.includes('nhà hàng') || nameLower.includes('hotel')) return 'Nhà hàng / Khách sạn';
+    if (nameLower.includes('ô tô') || nameLower.includes('mercedes') || nameLower.includes('haxaco')) return 'Ô tô';
+    return 'Khác';
+  }
+
+  showDetailItem(item: any) {
+    this.detailedItem = item;
+    this.cdr.markForCheck();
+  }
+  changePage(currentPage: number) {
+    this.pageNum = currentPage;
+    // If currently viewing a company's jobs, keep using by-organization endpoint
+    if (this.viewingCompanyId) {
+      this.fetchJobsByOrganization({
+        organizationId: this.viewingCompanyId,
+        jobId: this.viewingCurrentJobId,
+        paging: { page: this.pageNum, size: this.dataSource?.pageSize || 10 },
+      });
+      return;
+    }
+    if (this.authenticated) {
+      this.bodyUser.paging.page = this.pageNum;
+      this.getData(this.bodyUser);
+    }
+    else {
+      this.bodyGetData.paging.page = this.pageNum;
+      this.getData(this.bodyGetData);
+    }
+  }
+  onRequestFill(index: number) {
+    // Khi xóa 1 item trong trang hiện tại, gọi API lấy thêm để bù vào cuối danh sách trang này
+    const body = { ...this.bodyGetData };
+    // luôn lấy size=1 bản ghi tiếp theo kể từ trang hiện tại
+    body.paging = { page: this.pageNum + 1, size: 1 };
+    this.commonService.retrieveData([
+      new ApiModel(
+        'get list jobs',
+        environment.API_URI + ApiNameConstants.BS_JOB_SEARCH,
+        body,
+        ConstantsApp.POST
+      ),
+    ]).subscribe((res) => {
+      const extra = res[0]?.data?.[0];
+      if (!extra) return;
+      // chèn ngay lập tức vào vị trí vừa xóa
+      // Gọi xuống component con để insert trực tiếp
+      const listComp = (this as any).itemsListRef;
+      if (listComp && listComp.insertItemAt) {
+        listComp.insertItemAt(index, extra);
+      }
+      this.cdr.markForCheck();
+    });
+  }
+
+}

