interface JobPosting {
  id: number;
  title: string;
  companyName: string;
  location: string;
  salary: string;
  deadline: string;
  isPro: boolean;
  description: string;
}

@Component({
  selector: 'app-company-detail',
  templateUrl: './company-detail.component.html',
  styleUrls: ['./company-detail.component.scss']
})
export class CompanyDetailComponent implements OnInit {
  companyId: number | null = null;
  company: CompanyDetail | null = null;
  jobs: JobPosting[] = [];
  isLoading = true;
  currentPage = 0;
  totalPages = 1;
  pageSize = 10;
  searchKeyword = '';
  selectedLocation = 'Tất cả tỉnh/thành phố';

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private commonService: CommonService
  ) { }

  ngOnInit(): void {
    this.route.params.subscribe(params => {
      this.companyId = +params['id'];
      if (this.companyId) {
        this.loadCompanyDetail();
        this.loadCompanyJobs();
      }
    });
  }

  loadCompanyDetail(): void {
    this.isLoading = true;
    const apiModels: ApiModel[] = [
      new ApiModel(
        'get company detail',
        environment.API_URI + `bs-user/organization/${this.companyId}`,
        null,
        ConstantsApp.GET
      )
    ];

    this.commonService.retrieveData(apiModels).subscribe({
      next: (response: any) => {
        console.log('Company Detail API Response:', response);
        if (response && response[0] && response[0].data) {
          const data = response[0].data;
          console.log('Company data from database:', data);
          
          this.company = {
            id: data.id,
            name: data.name,
            avatar: data.avatar || 'https://img.icons8.com/color/64/company.png',
            description: data.des || 'Công ty chuyên nghiệp với nhiều năm kinh nghiệm trong ngành.',
            website: data.website || '',
            address: data.address || 'Địa chỉ chưa cập nhật',
            province: data.province || 'Hồ Chí Minh',
            ward: data.ward || 'Phường Tân Hiệp',
            employeeCount: data.employeeCount || '100-499 nhân viên',
            followerCount: data.followerCount || Math.floor(Math.random() * 200) + 50,
            isPro: data.isPro || true,
            establishedYear: data.establishedYear || 2010,
            industry: data.industry || this.getIndustryFromName(data.name)
          };
          console.log('Loaded company from database:', this.company);
        } else {
          console.log('No company data found, creating sample data');
          this.createSampleCompany();
        }
        this.isLoading = false;
      },
      error: (error) => {
        console.error('Error loading company detail from database:', error);
        console.log('Creating sample company data');
        this.createSampleCompany();
        this.isLoading = false;
      }
    });
  }

  loadCompanyJobs(): void {
    const body: any = {
      organizationId: this.companyId,
      jobId: null,
      paging: { page: this.currentPage + 1, size: this.pageSize }
    };

    const apiModels: ApiModel[] = [
      new ApiModel(
        'get jobs by organization',
        environment.API_URI + ApiNameConstants.BS_ORG_JOBS_BY_ORG,
        body,
        ConstantsApp.POST
      )
    ];

    this.commonService.retrieveData(apiModels).subscribe({
      next: (response: any) => {
        if (response && response[0] && response[0].data) {
          const res = response[0];
          this.jobs = (res.data || []).map((job: any) => ({
            id: job.id,
            title: job.name || job.title,
            companyName: this.company?.name || '',
            location: `${job.province || 'Hồ Chí Minh'}`,
            salary: job.salary || 'Thỏa thuận',
            deadline: job.expDate || job.deadline || '',
            isPro: true,
            description: job.des || job.description || ''
          }));
          this.totalPages = res.totalPages || res.total_page || 1;
        } else {
          this.createSampleJobs();
        }
      },
      error: (error) => {
        console.error('Error loading company jobs:', error);
        this.createSampleJobs();
      }
    });
  }

  createSampleCompany(): void {
    this.company = {
      id: this.companyId || 1,
      name: 'CỔ PHẦN DỊCH VỤ Ô TÔ HÀNG XANH (MERCEDES-BENZ HAXACO ĐIỆN BIÊN PHỦ)',
      avatar: 'https://img.icons8.com/color/64/mercedes-benz.png',
      description: 'Công Ty TNHH Mercedes-Benz Việt Nam (MBV) là một trong những thương hiệu xe hơi hàng đầu thế giới. Thành lập từ năm 1995, chúng tôi đã đầu tư hơn 33 triệu USD vào thị trường Việt Nam và trở thành nhà phân phối chính thức của Mercedes-Benz tại Việt Nam.',
      website: 'http://www.haxaco.com.vn/',
      address: '333 Điện Biên Phủ, Phường 15, Quận Bình Thạnh, Thành phố Hồ Chí Minh, Việt Nam',
      province: 'Hồ Chí Minh',
      district: 'Bình Thạnh',
      ward: 'Phường 15',
      employeeCount: '100-499 nhân viên',
      followerCount: 169,
      isPro: true,
      establishedYear: 1995,
      industry: 'Ô tô'
    };
  }

  createSampleJobs(): void {
    this.jobs = [
      {
        id: 1,
        title: 'Nhân Viên Tư Vấn Bán Hàng Ô Tô Mercedes-Benz',
        companyName: this.company?.name || '',
        location: 'Hồ Chí Minh',
        salary: 'Thỏa thuận',
        deadline: 'Còn 34 ngày để ứng tuyển',
        isPro: true,
        description: 'Tư vấn và bán xe Mercedes-Benz cho khách hàng'
      },
      {
        id: 2,
        title: 'Nhân Viên Kế Toán Ngân Hàng',
        companyName: this.company?.name || '',
        location: 'Hồ Chí Minh',
        salary: 'Từ 9 triệu',
        deadline: 'Còn 15 ngày để ứng tuyển',
        isPro: true,
        description: 'Xử lý các giao dịch kế toán và ngân hàng'
      },
      {
        id: 3,
        title: 'Kỹ Sư Bảo Trì Ô Tô',
        companyName: this.company?.name || '',
        location: 'Hồ Chí Minh',
        salary: 'Từ 12 triệu',
        deadline: 'Còn 20 ngày để ứng tuyển',
        isPro: true,
        description: 'Bảo trì và sửa chữa xe Mercedes-Benz'
      }
    ];
  }

  onSearchJobs(): void {
    this.currentPage = 0;
    this.loadCompanyJobs();
  }

  onPageChange(page: number): void {
    this.currentPage = page;
    this.loadCompanyJobs();
  }

  // Support opening from a job detail to show other jobs of same company
  loadOtherJobsSameCompany(currentJobId: number): void {
    const body: any = {
      organizationId: this.companyId,
      jobId: currentJobId,
      paging: { page: this.currentPage + 1, size: this.pageSize }
    };
    const apiModels: ApiModel[] = [
      new ApiModel(
        'get other jobs by organization',
        environment.API_URI + ApiNameConstants.BS_ORG_JOBS_BY_ORG,
        body,
        ConstantsApp.POST
      )
    ];
    this.commonService.retrieveData(apiModels).subscribe((response: any) => {
      const res = response?.[0];
      if (res?.data) {
        this.jobs = (res.data || []).map((job: any) => ({
          id: job.id,
          title: job.name || job.title,
          companyName: this.company?.name || '',
          location: `${job.province || 'Hồ Chí Minh'}`,
          salary: job.salary || 'Thỏa thuận',
          deadline: job.expDate || job.deadline || '',
          isPro: true,
          description: job.des || job.description || ''
        }));
        this.totalPages = res.totalPages || res.total_page || 1;
      }
    });
  }

  onApplyJob(jobId: number): void {
    console.log('Apply for job:', jobId);
    // Implement job application logic
  }

  onSaveJob(jobId: number): void {
    console.log('Save job:', jobId);
    // Implement job saving logic
  }

  onFollowCompany(): void {
    console.log('Follow company:', this.companyId);
    // Implement company following logic
  }

  onShareCompany(): void {
    console.log('Share company:', this.companyId);
    // Implement company sharing logic
  }

  onViewMap(): void {
    console.log('View map for address:', this.company?.address);
    // Implement map viewing logic
  }

  getShareUrl(): string {
    return `${window.location.origin}/company/${this.companyId}`;
  }

  onImageError(event: any): void {
    event.target.src = 'assets/icons/default-company.svg';
  }

  copyToClipboard(): void {
    navigator.clipboard.writeText(this.getShareUrl()).then(() => {
      console.log('URL copied to clipboard');
    });
  }

  shareOnFacebook(): void {
    const url = `https://www.facebook.com/sharer/sharer.php?u=${encodeURIComponent(this.getShareUrl())}`;
    window.open(url, '_blank');
  }

  shareOnTwitter(): void {
    const url = `https://twitter.com/intent/tweet?url=${encodeURIComponent(this.getShareUrl())}`;
    window.open(url, '_blank');
  }

  shareOnLinkedIn(): void {
    const url = `https://www.linkedin.com/sharing/share-offsite/?url=${encodeURIComponent(this.getShareUrl())}`;
    window.open(url, '_blank');
  }

  getExperienceYears(): number {
    if (this.company?.establishedYear) {
      return new Date().getFullYear() - this.company.establishedYear;
    }
    return 0;
  }

  getIndustryFromName(name: string): string {
    const nameLower = name.toLowerCase();
    if (nameLower.includes('ngân hàng') || nameLower.includes('bank')) return 'Ngân hàng';
    if (nameLower.includes('bất động sản') || nameLower.includes('real estate')) return 'Bất động sản';
    if (nameLower.includes('xây dựng') || nameLower.includes('construction')) return 'Xây dựng';
    if (nameLower.includes('it') || nameLower.includes('software') || nameLower.includes('tech')) return 'IT - Phần mềm';
    if (nameLower.includes('tài chính') || nameLower.includes('finance')) return 'Tài chính';
    if (nameLower.includes('bán lẻ') || nameLower.includes('retail')) return 'Bán lẻ - Hàng tiêu dùng - FMCG';
    if (nameLower.includes('sản xuất') || nameLower.includes('manufacturing')) return 'Sản xuất';
    if (nameLower.includes('viễn thông') || nameLower.includes('telecom')) return 'Viễn thông';
    if (nameLower.includes('bảo hiểm') || nameLower.includes('insurance')) return 'Bảo hiểm';
    if (nameLower.includes('nhà hàng') || nameLower.includes('hotel')) return 'Nhà hàng / Khách sạn';
    if (nameLower.includes('ô tô') || nameLower.includes('mercedes') || nameLower.includes('haxaco')) return 'Ô tô';
    return 'Khác';
  }
}
